阅读以下代码，输出结果是什么？

var x = 1;
function foo() {
  console.log(x);
  if (true) {
    let x = 2;
  }
}
foo();

阅读代码并判断输出顺序：

console.log(1);
setTimeout(() => console.log(2), 0);
Promise.resolve().then(() => {
  console.log(3);
  return Promise.resolve();
}).then(() => console.log(4));
console.log(5);

执行以下代码，输出顺序是什么？

Promise.resolve().then(() => {
  console.log(0);
  return Promise.resolve(4);
}).then((res) => {
  console.log(res);
});

Promise.resolve().then(() => {
  console.log(1);
}).then(() => {
  console.log(2);
}).then(() => {
  console.log(3);
}).then(() => {
  console.log(5);
});

执行以下代码，输出顺序是什么？

console.log('script start');

setTimeout(function() {
  console.log('setTimeout');
}, 0);

Promise.resolve().then(function() {
  console.log('promise1');
}).then(function() {
  console.log('promise2');
});

console.log('script end');
